import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/utils/cn";

/* в”Җв”Җ Variants в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
const buttonGroupVariants = cva(
  "flex",
  {
    variants: {
      direction: {
        // мҲҳнҸү вҖ” к°•мЎ° лІ„нҠјмқҖ мҡ°мёЎ
        horizontal: "flex-row items-center",
        // мҲҳм§Ғ вҖ” к°•мЎ° лІ„нҠјмқҖ мІ« лІҲм§ё, лӘЁл“  лІ„нҠј width лҸҷмқј
        vertical: "flex-col w-full [&>*]:w-full",
      },
      gap: {
        sm: "",   // лІ„нҠј 2к°ң: gap-2 (8px) вҖ” children мҲҳм—җ л”°лқј мһҗлҸҷ
        md: "",   // лІ„нҠј 3к°ң мқҙмғҒ: gap-3 (12px)
      },
    },
    defaultVariants: {
      direction: "horizontal",
    },
  }
);

/* в”Җв”Җ Props в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
export interface ButtonGroupProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof buttonGroupVariants> {
  direction?: "horizontal" | "vertical";
}

/* в”Җв”Җ Component в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
function ButtonGroup({
  className,
  direction = "horizontal",
  children,
  ...props
}: ButtonGroupProps) {
  const count = React.Children.count(children);

  // лІ„нҠј 2к°ң: gap-2(8px), 3к°ң мқҙмғҒ: gap-3(12px)
  const gapClass = count <= 2 ? "gap-2" : "gap-3";

  return (
    <div
      className={cn(
        buttonGroupVariants({ direction }),
        gapClass,
        className
      )}
      {...props}
    >
      {children}
    </div>
  );
}

export { ButtonGroup };